<div id="redline-viewer"></div>

<script>
const diffs = [
    {type: "delete", start_index: 67, end_index: 71},
    {type: "insert", index: 67, text: "30"}
];

function renderRedlineDiff(diffs) {
    const viewerDiv = document.getElementById('redline-viewer');

    diffs.forEach(diff => {
        if (diff.type === 'delete') {
            viewerDiv.innerHTML += `<del>${diff.text}</del>`;
        } else if (diff.type === 'insert') {
            viewerDiv.innerHTML += `<ins>${diff.text}</ins>`;
        }
    });
}

renderRedlineDiff(diffs);
</script>
```

